import{_ as t,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"壓縮恢復: 技能自動恢復 | opencode-agent-skills","description":"學習 opencode-agent-skills 的壓縮恢復機制。在會話壓縮後自動恢復技能列表，使用 synthetic 消息保持技能可用。","frontmatter":{"title":"壓縮恢復: 技能自動恢復 | opencode-agent-skills","sidebarTitle":"壓縮後技能不丟","subtitle":"壓縮恢復: 技能自動恢復","description":"學習 opencode-agent-skills 的壓縮恢復機制。在會話壓縮後自動恢復技能列表，使用 synthetic 消息保持技能可用。","tags":["上下文管理","會話持久","高級功能"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),l={name:"zh-tw/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function n(o,a,r,d,p,h){return s(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="上下文壓縮恢復機制" tabindex="-1">上下文壓縮恢復機制 <a class="header-anchor" href="#上下文壓縮恢復機制" aria-label="Permalink to &quot;上下文壓縮恢復機制&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>理解插件如何在會話壓縮後保持技能可用</li><li>知道壓縮恢復的觸發時機和執行流程</li><li>能夠驗證壓縮恢復是否正常工作</li><li>理解 synthetic 消息在恢復機制中的作用</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>在長會話中，OpenCode 會執行<strong>上下文壓縮</strong>（Context Compaction）以節省 Token。壓縮後的會話只保留最近的消息，早期歷史記錄（包括之前注入的技能內容）會被移除。</p><p>這導致一個問題：如果技能內容被壓縮掉了，AI 就不再知道有哪些技能可用，也無法使用已加載的技能。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>壓縮恢復機制是<strong>自動運行</strong>的，你無需手動干預。但了解它的原理後，你可以在以下場景排查問題：</p><ul><li>長會話中 AI 突然&quot;忘記&quot;了技能</li><li>需要調試技能在壓縮後的可用性</li><li>想理解插件的會話管理策略</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什麼是上下文壓縮" tabindex="-1">什麼是上下文壓縮？ <a class="header-anchor" href="#什麼是上下文壓縮" aria-label="Permalink to &quot;什麼是上下文壓縮？&quot;">​</a></h3><p>OpenCode 會話隨著消息增多會越來越長，當 Token 使用量接近上限時，系統會自動執行<strong>上下文壓縮</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[會話初始] → [消息 1] → [消息 2] → ... → [消息 50]</span></span>
<span class="line"><span>                          ↑ 壓縮點：只保留最近 10 條消息</span></span></code></pre></div><p>壓縮後，早期消息（包括技能注入內容）會被移除，AI 只能看到最近的消息歷史。</p><h3 id="壓縮恢復機制的工作原理" tabindex="-1">壓縮恢復機制的工作原理 <a class="header-anchor" href="#壓縮恢復機制的工作原理" aria-label="Permalink to &quot;壓縮恢復機制的工作原理&quot;">​</a></h3><p>插件監聽 <code>session.compacted</code> 事件，一旦檢測到壓縮發生，立即執行以下恢復操作：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[會話壓縮觸發] --&gt; B[session.compacted 事件]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{已啟用 Superpowers?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|是| D[重新注入 Superpowers 提示]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|否| E[跳過 Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[重新注入技能列表]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[清空已加載技能記錄]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[恢復完成]</span></span></code></pre></div><p><strong>關鍵點</strong>：</p><ul><li>恢復是<strong>自動的</strong>，無需手動觸發</li><li>恢復後的技能列表包含<strong>所有發現的技能</strong>（不僅僅是之前加載的）</li><li>已加載技能的記錄會被清空，允許 AI 重新評估需要哪些技能</li></ul><h3 id="synthetic-消息的作用" tabindex="-1">Synthetic 消息的作用 <a class="header-anchor" href="#synthetic-消息的作用" aria-label="Permalink to &quot;Synthetic 消息的作用&quot;">​</a></h3><p>插件使用 <strong>Synthetic Message Injection</strong> 機制注入內容：</p><table tabindex="0"><thead><tr><th>屬性</th><th>值</th><th>含義</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>AI 不會對注入內容本身進行回覆</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>標記為系統生成內容，不計入用戶輸入，不在 UI 顯示</td></tr></tbody></table><p>這意味著壓縮恢復注入的內容：</p><ul><li>對用戶完全透明（看不到）</li><li>不消耗用戶消息配額</li><li>但會被 AI 讀取並理解</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><p>本教程需要：</p><ul><li>已安裝 OpenCode Agent Skills 插件</li><li>理解技能加載的基礎知識</li><li>一個長會話用於測試壓縮效果</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>無需額外準備，壓縮恢復機制是插件內置功能。</p></div><h2 id="跟我做-驗證壓縮恢復效果" tabindex="-1">跟我做：驗證壓縮恢復效果 <a class="header-anchor" href="#跟我做-驗證壓縮恢復效果" aria-label="Permalink to &quot;跟我做：驗證壓縮恢復效果&quot;">​</a></h2><h3 id="第-1-步-啟動新會話" tabindex="-1">第 1 步：啟動新會話 <a class="header-anchor" href="#第-1-步-啟動新會話" aria-label="Permalink to &quot;第 1 步：啟動新會話&quot;">​</a></h3><p><strong>為什麼</strong> 驗證會話初始化時技能列表是否正常注入</p><p>啟動一個新會話，輸入任何消息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你好</span></span></code></pre></div><p><strong>你應該看到</strong>：AI 正常回覆，並在後台自動注入了技能列表（對用戶不可見）</p><h3 id="第-2-步-加載一個技能" tabindex="-1">第 2 步：加載一個技能 <a class="header-anchor" href="#第-2-步-加載一個技能" aria-label="Permalink to &quot;第 2 步：加載一個技能&quot;">​</a></h3><p><strong>為什麼</strong> 確保技能內容被注入到上下文</p><p>調用 <code>use_skill</code> 工具：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用 get_available_skills 查看可用技能，然後用 use_skill 加載其中一個技能</span></span></code></pre></div><p><strong>你應該看到</strong>：AI 列出可用技能，然後加載你選擇的技能</p><h3 id="第-3-步-觸發上下文壓縮" tabindex="-1">第 3 步：觸發上下文壓縮 <a class="header-anchor" href="#第-3-步-觸發上下文壓縮" aria-label="Permalink to &quot;第 3 步：觸發上下文壓縮&quot;">​</a></h3><p><strong>為什麼</strong> 模擬長會話場景，觸發 OpenCode 的壓縮機制</p><p>持續發送消息，模擬長對話：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>消息 1：測試內容</span></span>
<span class="line"><span>消息 2：繼續測試</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（重複發送 20-30 條消息）</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>隨著消息增多，會話歷史變長</li><li>達到一定長度後，OpenCode 自動執行壓縮</li><li>壓縮後，早期消息（包括技能注入）被移除</li></ul><h3 id="第-4-步-檢查恢復效果" tabindex="-1">第 4 步：檢查恢復效果 <a class="header-anchor" href="#第-4-步-檢查恢復效果" aria-label="Permalink to &quot;第 4 步：檢查恢復效果&quot;">​</a></h3><p><strong>為什麼</strong> 驗證壓縮後技能列表是否被重新注入</p><p>壓縮後，再次讓 AI 使用技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>幫我使用 git-helper 技能創建新分支（假設你已安裝 git-helper 技能）</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>AI 仍然知道有哪些技能可用（證明技能列表已恢復）</li><li>AI 能夠正常加載和使用技能（證明技能功能未受壓縮影響）</li></ul><h3 id="第-5-步-驗證-synthetic-消息注入" tabindex="-1">第 5 步：驗證 Synthetic 消息注入 <a class="header-anchor" href="#第-5-步-驗證-synthetic-消息注入" aria-label="Permalink to &quot;第 5 步：驗證 Synthetic 消息注入&quot;">​</a></h3><p><strong>為什麼</strong> 確認恢復機制使用的是 synthetic 消息，不會干擾對話</p><p>如果插件支持，可以檢查會話消息歷史（取決於 OpenCode 功能）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用調試工具查看會話消息歷史</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>恢復的技能列表消息標記為 <code>synthetic: true</code></li><li>這些消息不會顯示在正常對話界面</li></ul><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>完成上述步驟後，你應該能夠確認：</p><ul><li>[ ] 長會話中 AI 仍能訪問技能列表</li><li>[ ] 壓縮後技能加載功能正常工作</li><li>[ ] 恢復過程對用戶完全透明</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="問題-1-壓縮後-ai-說-找不到技能" tabindex="-1">問題 1：壓縮後 AI 說&quot;找不到技能&quot; <a class="header-anchor" href="#問題-1-壓縮後-ai-說-找不到技能" aria-label="Permalink to &quot;問題 1：壓縮後 AI 說&quot;找不到技能&quot;&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>插件未正確監聽 <code>session.compacted</code> 事件</li><li>技能目錄路徑發生變化</li></ul><p><strong>解決方法</strong>：</p><ol><li><p><strong>驗證壓縮事件是否觸發</strong></p><ul><li>通過「跟我做」中的第 3 步和第 4 步，確認壓縮後 AI 仍能訪問技能列表</li><li>如果 AI 能正常使用技能，說明壓縮恢復機制工作正常</li></ul></li><li><p><strong>檢查插件是否正確加載</strong></p><ul><li>重啟 OpenCode</li><li>啟動新會話後，讓 AI 列出可用技能（<code>get_available_skills</code>）</li><li>如果能看到技能列表，說明插件已正確加載</li></ul></li></ol><h3 id="問題-2-恢復的技能列表為空" tabindex="-1">問題 2：恢復的技能列表為空 <a class="header-anchor" href="#問題-2-恢復的技能列表為空" aria-label="Permalink to &quot;問題 2：恢復的技能列表為空&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>技能發現路徑中沒有技能</li><li>技能文件格式錯誤</li></ul><p><strong>解決方法</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手動查詢可用技能</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">使用</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 查看技能列表</span></span></code></pre></div><p>如果返回空列表，檢查技能目錄和文件格式。</p><h3 id="問題-3-壓縮後已加載技能狀態丟失" tabindex="-1">問題 3：壓縮後已加載技能狀態丟失 <a class="header-anchor" href="#問題-3-壓縮後已加載技能狀態丟失" aria-label="Permalink to &quot;問題 3：壓縮後已加載技能狀態丟失&quot;">​</a></h3><p><strong>這是預期行為</strong>，不是 Bug。恢復機制會清空 <code>loadedSkillsPerSession</code> 記錄，允許 AI 重新評估需要哪些技能。</p><p><strong>解決方法</strong>：AI 會根據上下文自動決定是否重新加載技能，無需手動干預。</p><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>壓縮恢復機制通過以下方式確保技能在長會話中的可用性：</p><ol><li><strong>監聽壓縮事件</strong>：自動檢測 <code>session.compacted</code> 事件</li><li><strong>重新注入技能列表</strong>：使用 <code>&lt;available-skills&gt;</code> 標籤注入所有技能</li><li><strong>可選 Superpowers 恢復</strong>：如果啟用，同時恢復 Superpowers 提示</li><li><strong>使用 Synthetic 消息</strong>：恢復過程對用戶透明，不影響對話</li><li><strong>重置已加載記錄</strong>：清空已加載技能集合，允許重新評估</li></ol><p>這套機制確保了：</p><ul><li>長會話中技能始終可用</li><li>恢復過程自動化且無感知</li><li>AI 可以根據最新上下文決定使用哪些技能</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../faq/troubleshooting/">常見問題排查</a></strong>。</p><p>你會學到：</p><ul><li>常見錯誤和異常的處理方法</li><li>壓縮恢復相關的排查技巧</li><li>其他使用問題的解決方案</li></ul></blockquote><hr><h2 id="附錄-源碼參考" tabindex="-1">附錄：源碼參考 <a class="header-anchor" href="#附錄-源碼參考" aria-label="Permalink to &quot;附錄：源碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看源碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路徑</th><th>行號</th></tr></thead><tbody><tr><td>壓縮事件監聽</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>首次消息初始化</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>技能列表注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Synthetic 消息注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>會話狀態管理</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>關鍵變量</strong>：</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code>：記錄已完成初始化的會話 ID</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code>：記錄每個會話已加載的技能名稱</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>injectSkillsList()</code>：注入可用技能列表到會話</li><li><code>injectSyntheticContent()</code>：使用 synthetic 消息注入內容</li><li><code>getSessionContext()</code>：獲取會話的 model 和 agent 信息</li></ul></details>`,85)])])}const u=t(l,[["render",n]]);export{g as __pageData,u as default};
